CREATE VIEW `dim_high_book_record_config_view` (`product_id` COMMENT "产品id", `book_id` COMMENT "书籍id", `start_time` COMMENT "开始测试时间", `end_time` COMMENT "结束测试时间", `item_id` COMMENT "配置id，开发用来识别哪个配置的", `create_time` COMMENT "创建时间")
COMMENT "high点测试：测试信息配置表" AS (SELECT `ods`.`ods_tidb_readernovel_mysql_highbookrecord`.`product_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord`.`bookid` AS `book_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord`.`starttime` AS `start_time`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord`.`endtime` AS `end_time`, CASE WHEN (`ods`.`ods_tidb_readernovel_mysql_highbookrecord`.`id` IS NULL) THEN 0 ELSE `ods`.`ods_tidb_readernovel_mysql_highbookrecord`.`id` END AS `item_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord`.`createtime` AS `create_time`
FROM `ods`.`ods_tidb_readernovel_mysql_highbookrecord` UNION ALL SELECT `ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`.`product_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`.`bookid` AS `book_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`.`starttime` AS `start_time`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`.`endtime` AS `end_time`, CASE WHEN (`ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`.`id` IS NULL) THEN 0 ELSE `ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`.`id` END AS `item_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`.`createtime` AS `create_time`
FROM `ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`
WHERE (right(`ods`.`ods_tidb_readernovel_mysql_highbookrecord_tl`.`bookid`, 3)) = 445 UNION ALL SELECT `ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`.`product_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`.`bookid` AS `book_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`.`starttime` AS `start_time`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`.`endtime` AS `end_time`, CASE WHEN (`ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`.`id` IS NULL) THEN 0 ELSE `ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`.`id` END AS `item_id`, `ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`.`createtime` AS `create_time`
FROM `ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`
WHERE (right(`ods`.`ods_tidb_readernovel_mysql_highbookrecord_ko`.`bookid`, 3)) = 436);
